// // This module decrements a 2-bit binary counter on the rising edge of the clock when the enable signal is high and resets to zero when the reset signal is high.
module Counter2bit (
    input clk,
    input rst,
    input en,
    output reg [1:0] count
);
    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= 2'b00;
        else if (en)
            count <= count + 1;
    end
endmodule
